+        const pos = std.mem.indexOf(u8, line, marker) orelse return null;
+        const after = line[pos..];
+        const suffix_pos = std.mem.indexOf(u8, after, suffix) orelse return null;
+        const end = suffix_pos + suffix.len;
+        return after[0..end];
+    }
